import sys

# Read all input
input_data = sys.stdin.read().strip().split('\n')
t = int(input_data[0])

results = []

for i in range(1, t + 1):
    line = input_data[i].split('|')[0].strip()  # Ignore anything after '|'
    parts = line.split()  # Split by spaces
    name = parts[0]  # The name is the first word
    if 'apples' in line:
        N = int(parts[2])
        M = int(parts[5])
        results.append(N + M)
    elif 'candies' in line:
        N = int(parts[2])
        M = int(parts[5])
        if M <= N:
            results.append(N - M)
        else:
            results.append('INVALID')
    elif 'marbles' in line:
        N = int(parts[2])
        M = int(parts[7])
        if M <= N:
            results.append(N - M)
        else:
            results.append('INVALID')

# Print all results
for result in results:
    print(result)
